def bisection(f, a, b, tol=1e-7):
    if f(a) * f(b) > 0: return None
    mid = (a + b) / 2
    if (b - a) / 2 < tol or f(mid) == 0:
        return mid
    if f(a) * f(mid) < 0: 
        return bisection(f, a, mid, tol)
    else:
        return bisection(f, mid, b, tol)

if __name__ == "__main__":
    func = lambda x: x**3 - 1
    print(f"Root: {bisection(func, -5, 5)}")
